import { RuleTester } from 'eslint';
import { noParentImports } from "../../rules/no-parent-imports.js";
import { languageOptions } from "../../runtime.js";
const ruleTesterOptions = {
    languageOptions: {
        ...languageOptions,
        parserOptions: {
            ecmaFeatures: {
                jsx: true,
            },
        },
    },
};
const relativeImportWithinExtensionPoint = `
  import { util } from './utils';
`;
const relativeImportFromSubdirectory = `
  import { Component } from './components/Button';
`;
const relativeImportGoingUpWithinBoundary = `
  import { util } from '../utils';
`;
const relativeImportEscapingBoundary = `
  import { util } from '../shared/utils';
`;
const deeplyNestedImportEscapingBoundary = `
  import { util } from '../../../lib/utils';
`;
const npmPackageImport = `
  import { useState } from 'react';
`;
const hubspotExtensionsImport = `
  import { Text, Button } from '@hubspot/ui-extensions';
`;
const scopedPackageImport = `
  import { something } from '@company/package';
`;
describe('no-parent-imports', () => {
    describe('in cards directory', () => {
        const ruleTester = new RuleTester(ruleTesterOptions);
        ruleTester.run('no-parent-imports', noParentImports, {
            valid: [
                {
                    name: 'relative import within cards directory',
                    code: relativeImportWithinExtensionPoint,
                    filename: '/path/to/project/src/app/cards/Component.tsx',
                },
                {
                    name: 'relative import from subdirectory within cards',
                    code: relativeImportFromSubdirectory,
                    filename: '/path/to/project/src/app/cards/index.tsx',
                },
                {
                    name: 'npm package import',
                    code: npmPackageImport,
                    filename: '/path/to/project/src/app/cards/Component.tsx',
                },
                {
                    name: 'HubSpot UI Extensions import',
                    code: hubspotExtensionsImport,
                    filename: '/path/to/project/src/app/cards/Component.tsx',
                },
                {
                    name: 'scoped package import',
                    code: scopedPackageImport,
                    filename: '/path/to/project/src/app/cards/Component.tsx',
                },
                {
                    name: 'relative import going up but staying within cards',
                    code: relativeImportGoingUpWithinBoundary,
                    filename: '/path/to/project/src/app/cards/nested/Component.tsx',
                },
                {
                    name: 'deeply nested relative import staying within cards',
                    code: `import { util } from '../../utils';`,
                    filename: '/path/to/project/src/app/cards/nested/deep/Component.tsx',
                },
            ],
            invalid: [
                {
                    name: 'relative import escaping cards directory',
                    code: relativeImportEscapingBoundary,
                    filename: '/path/to/project/src/app/cards/Component.tsx',
                    errors: [
                        {
                            message: 'Imports from outside "cards" will fail at build time. Use npm workspaces to share code.',
                        },
                    ],
                },
                {
                    name: 'deeply nested import escaping cards directory',
                    code: deeplyNestedImportEscapingBoundary,
                    filename: '/path/to/project/src/app/cards/nested/deep/Component.tsx',
                    errors: [
                        {
                            message: 'Imports from outside "cards" will fail at build time. Use npm workspaces to share code.',
                        },
                    ],
                },
                {
                    name: 'import going up multiple levels and escaping',
                    code: `import { util } from '../../lib/utils';`,
                    filename: '/path/to/project/src/app/cards/nested/Component.tsx',
                    errors: [
                        {
                            message: 'Imports from outside "cards" will fail at build time. Use npm workspaces to share code.',
                        },
                    ],
                },
            ],
        });
    });
    describe('in extensions directory', () => {
        const ruleTester = new RuleTester(ruleTesterOptions);
        ruleTester.run('no-parent-imports', noParentImports, {
            valid: [
                {
                    name: 'relative import within extensions directory',
                    code: relativeImportWithinExtensionPoint,
                    filename: '/path/to/project/src/app/extensions/Component.tsx',
                },
                {
                    name: 'relative import from subdirectory within extensions',
                    code: relativeImportFromSubdirectory,
                    filename: '/path/to/project/src/app/extensions/index.tsx',
                },
                {
                    name: 'npm package import',
                    code: npmPackageImport,
                    filename: '/path/to/project/src/app/extensions/Component.tsx',
                },
                {
                    name: 'HubSpot UI Extensions import',
                    code: hubspotExtensionsImport,
                    filename: '/path/to/project/src/app/extensions/Component.tsx',
                },
                {
                    name: 'relative import going up but staying within extensions',
                    code: relativeImportGoingUpWithinBoundary,
                    filename: '/path/to/project/src/app/extensions/nested/Component.tsx',
                },
            ],
            invalid: [
                {
                    name: 'relative import escaping extensions directory',
                    code: relativeImportEscapingBoundary,
                    filename: '/path/to/project/src/app/extensions/Component.tsx',
                    errors: [
                        {
                            message: 'Imports from outside "extensions" will fail at build time. Use npm workspaces to share code.',
                        },
                    ],
                },
                {
                    name: 'deeply nested import escaping extensions directory',
                    code: deeplyNestedImportEscapingBoundary,
                    filename: '/path/to/project/src/app/extensions/nested/deep/Component.tsx',
                    errors: [
                        {
                            message: 'Imports from outside "extensions" will fail at build time. Use npm workspaces to share code.',
                        },
                    ],
                },
            ],
        });
    });
    describe('in settings directory', () => {
        const ruleTester = new RuleTester(ruleTesterOptions);
        ruleTester.run('no-parent-imports', noParentImports, {
            valid: [
                {
                    name: 'relative import within settings directory',
                    code: relativeImportWithinExtensionPoint,
                    filename: '/path/to/project/src/app/settings/Component.tsx',
                },
                {
                    name: 'relative import from subdirectory within settings',
                    code: relativeImportFromSubdirectory,
                    filename: '/path/to/project/src/app/settings/index.tsx',
                },
                {
                    name: 'npm package import',
                    code: npmPackageImport,
                    filename: '/path/to/project/src/app/settings/Component.tsx',
                },
                {
                    name: 'HubSpot UI Extensions import',
                    code: hubspotExtensionsImport,
                    filename: '/path/to/project/src/app/settings/Component.tsx',
                },
                {
                    name: 'relative import going up but staying within settings',
                    code: relativeImportGoingUpWithinBoundary,
                    filename: '/path/to/project/src/app/settings/nested/Component.tsx',
                },
            ],
            invalid: [
                {
                    name: 'relative import escaping settings directory',
                    code: relativeImportEscapingBoundary,
                    filename: '/path/to/project/src/app/settings/Component.tsx',
                    errors: [
                        {
                            message: 'Imports from outside "settings" will fail at build time. Use npm workspaces to share code.',
                        },
                    ],
                },
                {
                    name: 'deeply nested import escaping settings directory',
                    code: deeplyNestedImportEscapingBoundary,
                    filename: '/path/to/project/src/app/settings/nested/deep/Component.tsx',
                    errors: [
                        {
                            message: 'Imports from outside "settings" will fail at build time. Use npm workspaces to share code.',
                        },
                    ],
                },
            ],
        });
    });
    describe('in pages directory', () => {
        const ruleTester = new RuleTester(ruleTesterOptions);
        ruleTester.run('no-parent-imports', noParentImports, {
            valid: [
                {
                    name: 'relative import within pages directory',
                    code: relativeImportWithinExtensionPoint,
                    filename: '/path/to/project/src/app/pages/Component.tsx',
                },
                {
                    name: 'relative import from subdirectory within pages',
                    code: relativeImportFromSubdirectory,
                    filename: '/path/to/project/src/app/pages/index.tsx',
                },
                {
                    name: 'npm package import',
                    code: npmPackageImport,
                    filename: '/path/to/project/src/app/pages/Component.tsx',
                },
                {
                    name: 'HubSpot UI Extensions import',
                    code: hubspotExtensionsImport,
                    filename: '/path/to/project/src/app/pages/Component.tsx',
                },
                {
                    name: 'relative import going up but staying within pages',
                    code: relativeImportGoingUpWithinBoundary,
                    filename: '/path/to/project/src/app/pages/nested/Component.tsx',
                },
            ],
            invalid: [
                {
                    name: 'relative import escaping pages directory',
                    code: relativeImportEscapingBoundary,
                    filename: '/path/to/project/src/app/pages/Component.tsx',
                    errors: [
                        {
                            message: 'Imports from outside "pages" will fail at build time. Use npm workspaces to share code.',
                        },
                    ],
                },
                {
                    name: 'deeply nested import escaping pages directory',
                    code: deeplyNestedImportEscapingBoundary,
                    filename: '/path/to/project/src/app/pages/nested/deep/Component.tsx',
                    errors: [
                        {
                            message: 'Imports from outside "pages" will fail at build time. Use npm workspaces to share code.',
                        },
                    ],
                },
            ],
        });
    });
    describe('outside extension points', () => {
        const ruleTester = new RuleTester(ruleTesterOptions);
        ruleTester.run('no-parent-imports', noParentImports, {
            valid: [
                {
                    name: 'relative import in shared directory (not an extension point)',
                    code: relativeImportEscapingBoundary,
                    filename: '/path/to/project/src/app/shared/Component.tsx',
                },
                {
                    name: 'relative import in lib directory (not an extension point)',
                    code: `import { util } from '../../config/constants';`,
                    filename: '/path/to/project/src/lib/utils/helper.ts',
                },
                {
                    name: 'relative import in root src (not an extension point)',
                    code: `import { config } from './config';`,
                    filename: '/path/to/project/src/index.ts',
                },
            ],
            invalid: [],
        });
    });
    describe('edge cases', () => {
        const ruleTester = new RuleTester(ruleTesterOptions);
        ruleTester.run('no-parent-imports', noParentImports, {
            valid: [
                {
                    name: 'import with complex path staying within boundary',
                    code: `import { util } from './../components/../utils';`,
                    filename: '/path/to/project/src/app/cards/nested/Component.tsx',
                },
                {
                    name: 'import from direct parent staying within boundary',
                    code: `import { util } from '../';`,
                    filename: '/path/to/project/src/app/cards/nested/Component.tsx',
                },
            ],
            invalid: [
                {
                    name: 'import with complex path escaping boundary',
                    code: `import { util } from './../../../shared/utils';`,
                    filename: '/path/to/project/src/app/cards/Component.tsx',
                    errors: [
                        {
                            message: 'Imports from outside "cards" will fail at build time. Use npm workspaces to share code.',
                        },
                    ],
                },
                {
                    name: 'import barely escaping the boundary',
                    code: `import { util } from '../app/shared/utils';`,
                    filename: '/path/to/project/src/app/cards/Component.tsx',
                    errors: [
                        {
                            message: 'Imports from outside "cards" will fail at build time. Use npm workspaces to share code.',
                        },
                    ],
                },
            ],
        });
    });
});
